const crypto = require(''crypto'');
const item = $input.first();
const json = item.json ?? {};
const binary = item.binary ?? {};
const binaryKeys = Object.keys(binary);

function normalizeText(value) {
  return String(value ?? '').replace(/\r\n/g, '\n').replace(/\r/g, '\n');
}

function normalizeCheckbox(value, fallback) {
  if (Array.isArray(value)) {
    return value.length > 0;
  }
  if (typeof value === 'boolean') {
    return value;
  }
  if (typeof value === 'string') {
    const lowered = value.trim().toLowerCase();
    if (['true', '1', 'yes', 'on', 'enabled', 'aktiv', 'checked'].includes(lowered)) {
      return true;
    }
    if (['false', '0', 'no', 'off', 'disabled', 'deaktiviert'].includes(lowered)) {
      return false;
    }
  }
  return fallback;
}

function looksBinary(text) {
  const sample = String(text ?? '').slice(0, 4096);
  let suspicious = 0;
  for (const ch of sample) {
    const code = ch.charCodeAt(0);
    if (code === 0) {
      return true;
    }
    if (code < 32 && code !== 9 && code !== 10 && code !== 13) {
      suspicious += 1;
    }
  }
  return suspicious > Math.max(8, Math.floor(sample.length * 0.05));
}

function readBinaryField(fieldName) {
  const entry = binary[fieldName];
  if (!entry || !entry.data) {
    throw new Error(`Binary field ${fieldName} is present but empty.`);
  }
  const decoded = Buffer.from(entry.data, 'base64').toString('utf8');
  return {
    text: normalizeText(decoded),
    filename: entry.fileName || 'BLUEPRINT.md',
    mimeType: entry.mimeType || '',
    fieldName,
  };
}

const projectSlug = String(json.project_slug ?? '').trim();
const projectTitle = String(json.project_title ?? '').trim();
const llmCommandMode = String(json.llm_command_mode ?? 'opencode-run').trim();
const opencodeModel = String(json.opencode_model ?? '').trim();
const maxRuntimeMinutes = Number(json.max_runtime_minutes ?? 60);
const dryRun = normalizeCheckbox(json.dry_run, true);
const allowIssueScript = normalizeCheckbox(json.allow_github_issue_script_generation, true);
const allowGithubActionsFiles = normalizeCheckbox(json.allow_github_actions_files, true);
const extraInstruction = normalizeText(json.extra_instruction ?? '');

if (!/^[a-z0-9][a-z0-9-]{1,60}[a-z0-9]$/.test(projectSlug)) {
  throw new Error('project_slug darf nur Kleinbuchstaben, Zahlen und Bindestriche enthalten und muss 3ÔÇô62 Zeichen lang sein.');
}
if (projectTitle.length < 3 || projectTitle.length > 120) {
  throw new Error('project_title muss 3 bis 120 Zeichen lang sein.');
}
if (!['opencode-run', 'hermes-run', 'manual-terminal'].includes(llmCommandMode)) {
  throw new Error('llm_command_mode muss opencode-run, hermes-run oder manual-terminal sein.');
}
if (!Number.isInteger(maxRuntimeMinutes) || maxRuntimeMinutes < 5 || maxRuntimeMinutes > 180) {
  throw new Error('max_runtime_minutes muss eine ganze Zahl zwischen 5 und 180 sein.');
}

let blueprintSource = 'textarea';
let blueprintFilename = 'BLUEPRINT.md';
let blueprintMarkdown = '';

if (binary.blueprint_file && binary.blueprint_file.data) {
  const file = readBinaryField('blueprint_file');
  blueprintSource = 'file';
  blueprintFilename = file.filename || 'BLUEPRINT.md';
  blueprintMarkdown = file.text;
} else if (binaryKeys.length === 1) {
  const file = readBinaryField(binaryKeys[0]);
  blueprintSource = 'file';
  blueprintFilename = file.filename || 'BLUEPRINT.md';
  blueprintMarkdown = file.text;
} else if (binaryKeys.length > 1) {
  throw new Error('Mehrere Binary-Felder vorhanden, aber keines hei├ƒt blueprint_file. Bitte genau ein Blueprint-File hochladen oder blueprint_file verwenden.');
} else {
  const text = normalizeText(json.blueprint_text ?? '');
  if (!text.trim()) {
    throw new Error('Bitte BLUEPRINT.md hochladen oder Blueprint als Markdown-Text einf├╝gen.');
  }
  blueprintMarkdown = text;
}

blueprintMarkdown = normalizeText(blueprintMarkdown);
if (blueprintMarkdown.length < 50) {
  throw new Error('Blueprint muss mindestens 50 Zeichen enthalten.');
}
if (blueprintMarkdown.length > 300000) {
  throw new Error('Blueprint ├╝berschreitet die maximale L├ñnge von 300000 Zeichen.');
}
if (looksBinary(blueprintMarkdown)) {
  throw new Error('Blueprint enth├ñlt offensichtlich Bin├ñrdaten und wird abgelehnt.');
}

const runId = `run-${new Date().toISOString().replace(/[-:]/g, '').replace(/\.[0-9]{3}Z$/, 'Z')}-${crypto.randomBytes(3).toString('hex')}`;
const projectDir = `/opt/dev-fabric/workspaces/projects/${projectSlug}`;
const runDir = `/opt/dev-fabric/evidence/blueprint-bootstrap/${projectSlug}/${runId}`;
const logDir = `/opt/dev-fabric/logs/blueprint-bootstrap/${projectSlug}/${runId}`;
const blueprintSha256 = crypto.createHash('sha256').update(Buffer.from(blueprintMarkdown, 'utf8')).digest('hex');
const blueprintB64 = Buffer.from(blueprintMarkdown, 'utf8').toString('base64');
const initPromptB64 = '';
const extraInstructionB64 = extraInstruction ? Buffer.from(extraInstruction, 'utf8').toString('base64') : '';
const runInputFilename = `RUN_INPUT-${runId}.json`;
const uploadDir = '/tmp';
const finalInputPath = `${runDir}/RUN_INPUT.json`;
const statusPath = `${runDir}/status.json`;
const reportPath = `${runDir}/run-report.md`;
const agentLogPath = `${runDir}/agent.log`;
const shellQuote = (value) => JSON.stringify(String(value));
const startCommand = `set -euo pipefail && mkdir -p ${shellQuote(runDir)} ${shellQuote(logDir)} && mv ${shellQuote(`${uploadDir}/${runInputFilename}`)} ${shellQuote(finalInputPath)} && chmod 600 ${shellQuote(finalInputPath)} && ${shellQuote('/opt/dev-fabric/scripts/start_blueprint_bootstrap.sh')} --input-json ${shellQuote(finalInputPath)}`;
const readStatusCommand = `bash -lc ${shellQuote(`if [ -f ${shellQuote(statusPath)} ]; then jq -c . ${shellQuote(statusPath)}; else printf '%s\\n' ${shellQuote(JSON.stringify({ status: 'PENDING', message: 'status.json not written yet', run_dir: runDir }))}; fi`)}`;
const tailCommand = `tail -f ${agentLogPath}`;
const stopCommand = `tmux kill-session -t <session_name>`;
const attachCommand = `ssh runner@192.168.1.53\ntmux attach -t <session_name>`;
const reportCommand = `cat ${reportPath}`;
const redactedSummary = {
  project_slug: projectSlug,
  project_title: projectTitle,
  run_id: runId,
  blueprint_source: blueprintSource,
  blueprint_filename: blueprintFilename,
  blueprint_sha256: blueprintSha256,
  blueprint_length: blueprintMarkdown.length,
  llm_command_mode: llmCommandMode,
  opencode_model_present: Boolean(opencodeModel),
  max_runtime_minutes: maxRuntimeMinutes,
  dry_run: dryRun,
  allow_github_issue_script_generation: allowIssueScript,
  allow_github_actions_files: allowGithubActionsFiles,
  extra_instruction_present: Boolean(extraInstruction.trim()),
  blueprint_binary_field_count: binaryKeys.length,
};

return [{
  json: {
    project_slug: projectSlug,
    project_title: projectTitle,
    run_id: runId,
    project_dir: projectDir,
    run_dir: runDir,
    log_dir: logDir,
    blueprint_source: blueprintSource,
    blueprint_filename: blueprintFilename,
    blueprint_sha256: blueprintSha256,
    blueprint_length: blueprintMarkdown.length,
    blueprint_b64: blueprintB64,
    blueprint_markdown: blueprintMarkdown,
    init_prompt_b64: initPromptB64,
    llm_command_mode: llmCommandMode,
    opencode_model: opencodeModel,
    max_runtime_minutes: maxRuntimeMinutes,
    dry_run: dryRun,
    allow_github_issue_script_generation: allowIssueScript,
    allow_github_actions_files: allowGithubActionsFiles,
    extra_instruction_b64: extraInstructionB64,
    redacted_summary: redactedSummary,
    run_input_filename: runInputFilename,
    upload_dir: uploadDir,
    start_command: startCommand,
    read_status_command: readStatusCommand,
    attach_command: attachCommand,
    tail_command: tailCommand,
    stop_command: stopCommand,
    report_command: reportCommand,
    status_path: statusPath,
    report_path: reportPath,
    agent_log_path: agentLogPath,
  },
}];

const input = $input.first().json;
const runInput = {
  project_slug: input.project_slug,
  project_title: input.project_title,
  run_id: input.run_id,
  project_dir: input.project_dir,
  run_dir: input.run_dir,
  log_dir: input.log_dir,
  blueprint_source: input.blueprint_source,
  blueprint_filename: input.blueprint_filename,
  blueprint_sha256: input.blueprint_sha256,
  blueprint_length: input.blueprint_length,
  blueprint_b64: input.blueprint_b64,
  init_prompt_b64: input.init_prompt_b64,
  llm_command_mode: input.llm_command_mode,
  opencode_model: input.opencode_model,
  max_runtime_minutes: input.max_runtime_minutes,
  dry_run: input.dry_run,
  allow_github_issue_script_generation: input.allow_github_issue_script_generation,
  allow_github_actions_files: input.allow_github_actions_files,
  extra_instruction_b64: input.extra_instruction_b64,
};

const runInputJson = JSON.stringify(runInput, null, 2) + '\n';
const binaryData = {
  data: Buffer.from(runInputJson, 'utf8').toString('base64'),
  mimeType: 'application/json',
  fileName: input.run_input_filename,
};

return [{
  json: {
    ...input,
    run_input_json_size: Buffer.byteLength(runInputJson, 'utf8'),
    run_input_upload_path: input.upload_dir,
  },
  binary: {
    run_input_json: binaryData,
  },
}];

const prepared = $node["Prepare RUN_INPUT"].json;
const statusItem = $input.first().json ?? {};
const rawStatus = typeof statusItem.stdout === 'string' ? statusItem.stdout.trim() : '';
let statusJson = {};
if (rawStatus) {
  try {
    statusJson = JSON.parse(rawStatus);
  } catch (error) {
    statusJson = {
      status: 'UNKNOWN',
      parse_error: error.message,
      raw_stdout: rawStatus,
    };
  }
} else {
  statusJson = {
    status: 'PENDING',
    message: 'status.json output was empty',
  };
}

const sessionName = String(statusJson.session_name ?? '<session_name>');
const status = String(statusJson.status ?? 'UNKNOWN');
const message = [
  'Workflow gestartet.',
  '',
  `Projekt:`,
  prepared.project_title,
  '',
  `Projektordner:`,
  prepared.project_dir,
  '',
  `Run:`,
  prepared.run_id,
  '',
  `Evidence:`,
  prepared.run_dir,
  '',
  `Status:`,
  status,
  '',
  `Terminal ├Âffnen:`,
  'ssh runner@192.168.1.53',
  `tmux attach -t ${sessionName}`,
  '',
  `Live-Log:`,
  `tail -f ${prepared.run_dir}/agent.log`,
  '',
  `Stoppen:`,
  `tmux kill-session -t ${sessionName}`,
  '',
  `Report:`,
  `cat ${prepared.run_dir}/run-report.md`,
].join('\n');

return [{
  json: {
    message,
    status,
    status_json: statusJson,
    project_slug: prepared.project_slug,
    project_title: prepared.project_title,
    project_dir: prepared.project_dir,
    run_id: prepared.run_id,
    run_dir: prepared.run_dir,
    evidence_dir: prepared.run_dir,
    log_dir: prepared.log_dir,
    session_name: sessionName,
    attach_command: `tmux attach -t ${sessionName}`,
    tail_command: `tail -f ${prepared.run_dir}/agent.log`,
    stop_command: `tmux kill-session -t ${sessionName}`,
    report_command: `cat ${prepared.run_dir}/run-report.md`,
    run_input_upload_path: prepared.run_input_upload_path,
    run_input_filename: prepared.run_input_filename,
    start_command: prepared.start_command,
    read_status_command: prepared.read_status_command,
    upload_note: `RUN_INPUT.json wird per SSH-Dateiupload nach ${prepared.run_input_upload_path} ├╝bertragen und anschlie├ƒend nach ${prepared.run_dir} verschoben.`,
  },
}];
